def transform(grid):
    R,C=len(grid),len(grid[0])
    stripes=[]
    r=0
    while r<R:
        v=grid[r][0]; cnt=0
        while r<R and grid[r][0]==v: r+=1; cnt+=1
        stripes.append((v,cnt))
    total=sum(w for v,w in stripes)
    last_w=stripes[-1][1]
    # Try S = 2*(total - last_w) + last_w = 2*total - last_w
    S=2*total-last_w
    result=[[stripes[0][0]]*S for _ in range(S)]
    # Fill from center outward
    rev=list(reversed(stripes))
    offset=0
    for v,w in rev:
        center=S//2
        for d in range(offset,offset+w):
            ring_d=d
            for r in range(ring_d,S-ring_d):
                for c in range(ring_d,S-ring_d):
                    if r==ring_d or r==S-1-ring_d or c==ring_d or c==S-1-ring_d:
                        result[r][c]=v
        if offset==0:
            for r in range(S):
                for c in range(S):
                    d=min(r,c,S-1-r,S-1-c)
                    if d<w: result[r][c]=v
        offset+=w
    ring_at={}
    off2=0
    for v,w in stripes:
        for d in range(off2,off2+w): ring_at[d]=v
        off2+=w
    for r in range(S):
        for c in range(S):
            d=min(r,c,S-1-r,S-1-c)
            result[r][c]=ring_at.get(d,stripes[-1][0])
    return result

